import{_ as t,o as e,c as i,a2 as s}from"./chunks/framework.DZrHScmQ.js";const k=JSON.parse('{"title":"Claude Auth: Account vs Token","description":"","frontmatter":{},"headers":[],"relativePath":"ai-native/tooling/claude-auth.md","filePath":"ai-native/tooling/claude-auth.md"}'),l={name:"ai-native/tooling/claude-auth.md"};function n(d,a,h,o,r,p){return e(),i("div",null,[...a[0]||(a[0]=[s(`<h1 id="claude-auth-account-vs-token" tabindex="-1">Claude Auth: Account vs Token <a class="header-anchor" href="#claude-auth-account-vs-token" aria-label="Permalink to &quot;Claude Auth: Account vs Token&quot;">​</a></h1><p><strong>状态：Draft</strong></p><p>区分两件事：</p><ul><li><strong>Claude 账号 / OAuth profile</strong>：适合人类本地开发和临时操作。</li><li><strong>API token / service credential</strong>：适合程序、CI、服务器和无人值守任务。</li></ul><h2 id="选择规则" tabindex="-1">选择规则 <a class="header-anchor" href="#选择规则" aria-label="Permalink to &quot;选择规则&quot;">​</a></h2><table tabindex="0"><thead><tr><th>场景</th><th>用什么</th><th>原因</th></tr></thead><tbody><tr><td>Claude Code 日常交互</td><td>Claude 账号登录</td><td>人在场，权限和审批跟个人身份走</td></tr><tr><td>本地 <code>ant</code> CLI 调试</td><td>Claude 账号 / OAuth profile</td><td>不需要长期保存静态 key</td></tr><tr><td>本地脚本短期测试</td><td>优先账号；必要时用临时 token</td><td>降低 key 泄露风险</td></tr><tr><td>CI / 定时任务 / 服务器</td><td>API token 或工作负载身份</td><td>非交互、可轮换、可审计</td></tr><tr><td>多 workspace 切换</td><td>Named profile</td><td>避免用错 workspace</td></tr><tr><td>生产 Agent 访问第三方系统</td><td>Vault / 密钥管理系统</td><td>不把 secret 放进 prompt、代码或公共文档</td></tr></tbody></table><h2 id="不要混用" tabindex="-1">不要混用 <a class="header-anchor" href="#不要混用" aria-label="Permalink to &quot;不要混用&quot;">​</a></h2><p>同一进程里不要同时设置：</p><ul><li><code>ANTHROPIC_API_KEY</code></li><li><code>ANTHROPIC_AUTH_TOKEN</code></li></ul><p>如果两者都存在，容易打到错误身份或直接认证失败。</p><h2 id="常见坑" tabindex="-1">常见坑 <a class="header-anchor" href="#常见坑" aria-label="Permalink to &quot;常见坑&quot;">​</a></h2><ul><li>环境里的 <code>ANTHROPIC_API_KEY</code> 会覆盖账号 profile。</li><li>空字符串也可能被当作“已设置”。要真正 unset。</li><li>OAuth token 用 <code>Authorization: Bearer ...</code>，不是 <code>x-api-key</code>。</li><li>API key 不写进 <code>CLAUDE.md</code>、README、Prompt、Memory 或 issue。</li><li>飞书、GitHub、Linear 等第三方 token 也不进 Handbook。</li></ul><h2 id="推荐做法" tabindex="-1">推荐做法 <a class="header-anchor" href="#推荐做法" aria-label="Permalink to &quot;推荐做法&quot;">​</a></h2><h3 id="本地人类操作" tabindex="-1">本地人类操作 <a class="header-anchor" href="#本地人类操作" aria-label="Permalink to &quot;本地人类操作&quot;">​</a></h3><p>用账号登录，并用 profile 区分 workspace：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ant</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> auth</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> login</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --profile</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ant</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> profile</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> activate</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ant</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> auth</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span></code></pre></div><p>如果要确认 profile 没被 API key 覆盖：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">env</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ANTHROPIC_API_KEY</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ant</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> auth</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span></code></pre></div><h3 id="ci-服务器" tabindex="-1">CI / 服务器 <a class="header-anchor" href="#ci-服务器" aria-label="Permalink to &quot;CI / 服务器&quot;">​</a></h3><p>使用专门的 API token 或工作负载身份：</p><ul><li>最小权限</li><li>单独 secret store</li><li>定期轮换</li><li>不复用个人账号 token</li><li>日志中不打印 secret</li></ul><h3 id="agent-工具访问外部系统" tabindex="-1">Agent 工具访问外部系统 <a class="header-anchor" href="#agent-工具访问外部系统" aria-label="Permalink to &quot;Agent 工具访问外部系统&quot;">​</a></h3><p>优先放进 Vault 或宿主侧 secret manager。Agent 只看到工具，不直接看到 token。</p><p>如果必须由宿主执行带密钥操作，把它做成 custom tool：Agent 发请求，宿主用自己的凭据执行，再把结果返回。</p><h2 id="判断句" tabindex="-1">判断句 <a class="header-anchor" href="#判断句" aria-label="Permalink to &quot;判断句&quot;">​</a></h2><ul><li>人在终端前操作：优先 Claude 账号。</li><li>程序无人值守运行：用 token / 工作负载身份。</li><li>secret 会被 Agent 看到：方案不对，换 Vault、MCP credential 或宿主侧工具。</li></ul>`,26)])])}const u=t(l,[["render",n]]);export{k as __pageData,u as default};
